patch:
diff --git a/llvm/include/llvm/Analysis/ScalarEvolution.h b/llvm/include/llvm/Analysis/ScalarEvolution.h
index 7879622473ad..cea978e52023 100644
--- a/llvm/include/llvm/Analysis/ScalarEvolution.h
+++ b/llvm/include/llvm/Analysis/ScalarEvolution.h
@@ -1487,6 +1487,12 @@ private:
   /// predicate by splitting it into a set of independent predicates.
   bool ProvingSplitPredicate = false;

+  /// Re-entrancy guard to prevent recursive application/collection of loop
+  /// guards while we are already applying loop guards. This can happen when
+  /// building ranges during guard collection which in turn tries to apply loop
+  /// guards again.
+  bool InApplyLoopGuards = false;
+
   /// Memoized values for the getConstantMultiple
   DenseMap<const SCEV *, APInt> ConstantMultipleCache;

diff --git a/llvm/lib/Analysis/ScalarEvolution.cpp b/llvm/lib/Analysis/ScalarEvolution.cpp
index 8ab56025546e..cc96eb7baccf 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -15967,10 +15967,19 @@ const SCEV *ScalarEvolution::LoopGuards::rewrite(const SCEV *Expr) const {
 }

 const SCEV *ScalarEvolution::applyLoopGuards(const SCEV *Expr, const Loop *L) {
+  // Guard against re-entrancy: collecting loop guards can itself trigger range
+  // reasoning which attempts to apply loop guards again. Short-circuit to avoid
+  // unbounded recursion.
+  if (InApplyLoopGuards || !L)
+    return Expr;
+  SaveAndRestore<bool> Guard(InApplyLoopGuards, true);
   return applyLoopGuards(Expr, LoopGuards::collect(L, *this));
 }

 const SCEV *ScalarEvolution::applyLoopGuards(const SCEV *Expr,
                                              const LoopGuards &Guards) {
+  // Directly rewrite using the provided guards; do not apply the reentrancy
+  // guard here, as this overload does not perform guard collection and is safe
+  // to use even when we are in the middle of collecting guards.
   return Guards.rewrite(Expr);
 }

